  1	import { type FC, type FormEvent, useState } from 'react';
  2	import { EditModal } from 'src/modules/Providers/modals/EditModal/EditModal';
  3	import type {
  4	  EditModalProps,
  5	  OnConfirmHookType,
  6	} from 'src/modules/Providers/modals/EditModal/types';
  7	import { VDDKHelperTextShort } from 'src/modules/Providers/utils/components/VDDKHelperText/VDDKHelperText';
  8	import { validateVDDKImage } from 'src/modules/Providers/utils/validators/provider/vsphere/validateVDDKImage';
  9	import { TRUE_VALUE, YES_VALUE } from 'src/providers/create/utils/constants';
 10	import { EMPTY_VDDK_INIT_IMAGE_ANNOTATION } from 'src/providers/utils/constants';
 11	import { useForkliftTranslation } from 'src/utils/i18n';
 12	
 13	import { type Modify, ProviderModel, type V1beta1Provider } from '@kubev2v/types';
 14	import type { K8sModel } from '@openshift-console/dynamic-plugin-sdk';
 15	import { Alert, AlertVariant, Checkbox, Stack, StackItem } from '@patternfly/react-core';
 16	import { getAnnotations, getUseVddkAioOptimization } from '@utils/crds/common/selectors';
 17	
 18	import onUpdateVddkImageSettings from './onUpdateVddkImageSettings';
 19	
 20	type EditProviderVDDKImageProps = Modify<
 21	  EditModalProps,
 22	  {
 23	    resource: V1beta1Provider;
 24	    title?: string;
 25	    model?: K8sModel;
 26	    jsonPath?: string | string[];
 27	  }
 28	>;
 29	const EditProviderVDDKImage: FC<EditProviderVDDKImageProps> = (props) => {
 30	  const { t } = useForkliftTranslation();
 31	
 32	  const provider = props.resource;
 33	
 34	  const emptyVddkInitImage = getAnnotations(provider)?.[EMPTY_VDDK_INIT_IMAGE_ANNOTATION];
 35	  const useVddkAioOptimization = getUseVddkAioOptimization(provider);
 36	
 37	  const [emptyImage, setEmptyImage] = useState(emptyVddkInitImage);
 38	  const [useVddkAio, setUseVddkAio] = useState(useVddkAioOptimization);
 39	
 40	  const isEmptyImage = emptyImage === YES_VALUE;
 41	  const isUseVddkAio = useVddkAio === TRUE_VALUE;
 42	
 43	  // VddkTextInput is the default text input
 44	  const VddkTextInput = undefined;
 45	
 46	  // Validation of none empty vddk image, make sure it's not undefined
 47	  const validateNoneEmptyVDDKImage = (value: string | number) => validateVDDKImage(value ?? '');
 48	
 49	  const onChangeEmptyImage: (event: React.FormEvent<HTMLInputElement>, checked: boolean) => void = (
 50	    _event,
 51	    checked,
 52	  ) => {
 53	    if (checked) {
 54	      setEmptyImage(YES_VALUE);
 55	    } else {
 56	      setEmptyImage(undefined);
 57	    }
 58	  };
 59	
 60	  const onChangeUseVddkAio: (_event: FormEvent<HTMLInputElement>, checked: boolean) => void = (
 61	    _event,
 62	    checked,
 63	  ) => {
 64	    if (checked) {
 65	      setUseVddkAio(TRUE_VALUE);
 66	    } else {
 67	      setUseVddkAio(undefined);
 68	    }
 69	  };
 70	
 71	  const onConfirmHookForVddk: OnConfirmHookType = async ({ model, newValue, resource }) =>
 72	    onUpdateVddkImageSettings(model ?? ProviderModel, resource, {
 73	      isEmptyImage,
 74	      isUseVddkAio,
 75	      newValue,
 76	    });
 77	
 78	  const body = (
 79	    <Stack hasGutter>
 80	      <Alert variant={AlertVariant.warning} isInline title={<VDDKHelperTextShort />}>
 81	        <Checkbox
 82	          label={t(
 83	            'Skip VMware Virtual Disk Development Kit (VDDK) SDK acceleration (not recommended).',
 84	          )}
 85	          isChecked={isEmptyImage}
 86	          onChange={onChangeEmptyImage}
 87	          id="emptyVddkInitImage"
 88	          name="emptyVddkInitImage"
 89	        />
 90	      </Alert>
 91	      {!isEmptyImage && (
 92	        <StackItem isFilled={false}>
 93	          <Checkbox
 94	            label={t('Use VMware Virtual Disk Development Kit (VDDK) async IO Optimization.')}
 95	            isChecked={isUseVddkAio && !isEmptyImage}
 96	            onChange={onChangeUseVddkAio}
 97	            id="useVddkAioOptimization"
 98	            name="useVddkAioOptimization"
 99	            isDisabled={isEmptyImage}
100	          />
101	        </StackItem>
102	      )}
103	    </Stack>
104	  );
105	
106	  return (
107	    <EditModal
108	      {...props}
109	      jsonPath={'spec.settings.vddkInitImage'}
110	      title={props?.title ?? t('Edit VDDK init image')}
111	      label={t('VDDK init image')}
112	      model={ProviderModel}
113	      body={body}
114	      isVisible={!isEmptyImage}
115	      validationHook={validateNoneEmptyVDDKImage}
116	      InputComponent={VddkTextInput}
117	      onConfirmHook={onConfirmHookForVddk}
118	    />
119	  );
120	};
121	
122	export default EditProviderVDDKImage;

